var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 호환이 되는 부품을 쓰라고 내가 몇 번을 말해?","JPN":"おばさん！　部品を使うときは互換性があるものにしてって何度言ったらわかるの？","ENG":"Hey! How many times do I have to tell you, use compatible parts!","TWN":"喂！用相容的零件，我說過多少次了？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"입 다물고 네 할일이나 해, 고양아. 이게 스펙이 제일 좋은 조합이라고.","JPN":"黙って仕事しろ、猫。これが最もハイスペックになる組み合わせなんだよ。","ENG":"Shut up and focus on your task, kitty. This is the combination with the best specs.","TWN":"閉嘴，做你該做的事，小貓咪。這是性能最好的組合。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_31"},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아. 좋은 생각이 났어. 팔다리를 달아 준 다음 자기 마음에 들게 조립하라고 하자.","JPN":"あ、いいことを思いついたぜ。手足をつけてやって、こいつの好きなように組み立てさせるんだ。","ENG":"Ah. I have an idea. Let's give it arms and legs, and have it assemble itself.","TWN":"啊，我想到了一個好主意。我們給它裝上四肢，然後讓它自己裝吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"또 코드를 수정하라고? 우릴 죽일 셈이야?","JPN":"またコードを修正しろって？　私たちを殺すつもりか？","ENG":"You want us to change the code again? Are you trying to kill us?","TWN":"又修改程式碼？你是想玩死我們嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이제 남은 방법은 하나뿐이야. 하늘에 기도해서 우리를 대신해 줄 코드의 천사를 부르자.","JPN":"もう残された方法は1つだけ。神に祈って私たちの代わりになってくれるコードの天使を呼ぼう。","ENG":"There's only one option left. Let's pray for an angel of coding to come down and save us.","TWN":"現在就只剩下一個辦法了。對著上帝祈禱，召喚可以代替我們的程式碼天使過來。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"코드의 천사? 그런 편리한 방법이 있는데 왜 지금까지 쓰지 않았지?","JPN":"コードの天使？　そんな便利な方法があるなら、何で今まで使わなかったんだ？","ENG":"Angel of coding? Why didn't you call for them earlier?","TWN":"程式碼天使？既然有那麼簡單的辦法，為什麼到現在都不用？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……다들 제발 입 다물고 집중 좀 해!","JPN":"……頼むから黙って集中してくれ！","ENG":"...Everyone, be quiet and focus, please!","TWN":"……拜託大家都閉上嘴，專心幹活！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이봐, 제이나.","JPN":"おい、ジェイナ。","ENG":"Hey, Jaina.","TWN":"喂，婕娜。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 네?! 앗!","JPN":"あ、はい！？　あっ！","ENG":"Oh, huh?! Ah!","TWN":"啊，是？！啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"너무 놀라서 섭섭한데. 손에 든 것까지 떨어뜨리면 내가 괜히 머쓱해지잖아.","JPN":"そんなに驚かれるとは。手に持っていたものまで落とすほどだなんて、ちょっと申し訳ないな。","ENG":"I didn't think you'd be that surprised. Now it's awkward. You even dropped something.","TWN":"露出這麼驚訝的表情，我可是會很傷心的喔。而且害你手裡的東西掉了，我也會尷尬。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"음? 이건…… 주사위?","JPN":"うん？　これは……サイコロ？","ENG":"Hmm? This is... Dice?","TWN":"嗯？這是……骰子？"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……네. 안토노프 중장님께서 주신 주사위에요.","JPN":"……はい、アントノフ中将から頂いたサイコロです。","ENG":"...Yes. Lieutenant General Antonov gave those dice to me.","TWN":"……是的，安東諾夫中將給的骰子。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"사령관님께서?","JPN":"司令官が？","ENG":"The Commander?","TWN":"司令官？"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 그 사람……. 그러니까, 도미닉의 소지품이라고 하셨어요.","JPN":"はい。あの人……ドミニークの所持品だそうです。","ENG":"Yes. She said it was that person's... I mean, Dominic's.","TWN":"是的，那個人……說是多明尼克的隨身物品。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"참 이상하죠. 리플레이서 퀸과는 분명히 선을 그은 줄 알았는데.","JPN":"変ですよね。リプレイサー・クイーンとは完全に無関係になったと思っていたのですが。","ENG":"It's odd. I thought I drew the line between me and Replacer Queen.","TWN":"真奇怪。我以為已經和克隆·女皇劃清界限了呢。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"의문이 머릿속에서 떠나지 않거든요. 그렇게 무책임한 여자가 왜 이 자에게 집착했는지.","JPN":"疑問が頭から離れないんです。なぜあれほど無責任な女が、この者には執着していたのか。","ENG":"But I can't stop wondering. Why someone as reckless as her was obsessed with him.","TWN":"我的腦海裡一直有一個疑問，如此不負責的女人為什麼要執著於他呢。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그거야 당연히 궁금할 수밖에 없지.","JPN":"それは気になって当然だ。","ENG":"Of course you're curious.","TWN":"你的好奇是對的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"노바급 리액터를 찾으러 다닐 때 자기 입으로 말하지 않았던가?","JPN":"ノヴァ級リアクターを捜索していたとき、言ってただろう？","ENG":"Didn't you say it yourself? When you were looking for the Nova-Class Reactor.","TWN":"在尋找諾瓦反應爐時，你不是親口說過嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"리플레이서 퀸과 다르다는 사실을 증명하고 싶다고.","JPN":"リプレイサー・クイーンとは違うことを証明したいって。","ENG":"You said you wanted to prove that you were different from Replacer Queen.","TWN":"想證明自己和克隆·女皇不一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그럼 오히려 상대가 누군지 더 철저하게 알아야지. 적을 이기려면 적에 대해 알아야 하는 것처럼.","JPN":"だったら、当然相手について徹底的に知らないといけない。敵に打ち勝つには敵を知らなければいけないようにな。","ENG":"Then it's important to get more information about her. You have to know your enemy.","TWN":"那反倒更應該查清楚對手是誰了。俗話說，知己知彼百戰百勝嘛。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"아무것도 모르고 싸워서 이기는 건 나 같은 사람에게나 가능한 일이라고.","JPN":"なんの情報もなしに戦って勝てるなんていう技は、俺みたいな人間にこそできることなんだ。","ENG":"Beating opponents while knowing nothing about them is a trick only someone like I can pull.","TWN":"打沒有準備的仗，只有像我這樣的人才能贏，哈哈哈。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……대령님도 농담은 서투시네요.","JPN":"……大佐は冗談は下手なんですね。","ENG":"...You're not talented with jokes, are you?","TWN":"……上校也不會開玩笑呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"들켰군. 사과의 의미로 이 막 데운 피자를 소령에게 나눠 주도록 하지.","JPN":"バレたか。謝罪の意味合いを込めて、このアツアツのピザを少佐にも分けてやろう。","ENG":"You got me. Take this slice of pizza as an apology. I just heated it up.","TWN":"被你發現了。作為賠禮，我把這個剛熱好的披薩分給你吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"해적 녀석들이 가져 온 컨테이너에 있었다더군. 냉동이긴 해도 여기선 사치품이야.","JPN":"海賊どもが持ってきたやつがコンテナに入っていたんだ。冷凍とはいえ、ここでは貴重なものなんだぞ。","ENG":"It was in a container those Pirates brought along. It's frozen pizza, but it's still better than anything else we'd get here.","TWN":"從那些海盜帶來的補給裡拿來的，雖然是冷凍披薩，但在這裡也是奢侈品了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"가, 감사합니다. 하읍……","JPN":"あ、ありがとうございます。パクッ……","ENG":"Th-thank you. *Bite*","TWN":"謝，謝謝。哈……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그래서, 주사위를 보니까 뭔가 좀 떠오르던가?","JPN":"それで、サイコロを見て何か思い出したか？","ENG":"So, did you remember anything while looking at the dice?","TWN":"所以，關於骰子，你還能記起什麼嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아뇨. 아무것도 떠오르지 않았어요.","JPN":"いいえ、何も。","ENG":"No. Nothing.","TWN":"沒有，什麼都沒想到。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서의 시설에서는 원하지 않아도 기억이 떠올랐는데……","JPN":"リプレイサーの施設にいるときは、嫌でも思い浮かんだのに……","ENG":"I remembered things I didn't even ask for, back at the Replacer facility...","TWN":"在克隆集團的設施裡，雖然不願意，但我還是回憶了一下……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"사실은 리플레이서 퀸에게 그 남자가 그렇게 중요하지 않았던 걸까요?","JPN":"実はリプレイサー・クイーンにとって、あの男はそこまで重要ではなかったのでしょうか？","ENG":"Maybe he wasn't of much importance to Replacer Queen.","TWN":"其實對於克隆·女皇來說，那個男人真的那麼重要嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"글쎄. 그 두 명 관계는 나도 사령관님께 전해 들었던 게 전부라서.","JPN":"さぁな。あいにく二人の関係性については司令官から聞いたことがすべてでな。","ENG":"I'm not sure. What the Commander told me is all I know about those two.","TWN":"這個嘛。關於那二個人的關係，我也都是聽司令官說的。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이러쿵저러쿵 떠들어도 네가 아는 것과 큰 차이는 없을 것 같군.","JPN":"あれこれ言ってみても、君の知っていることと大きくは変わらないだろう。","ENG":"I feel like there isn't any new information to be shared.","TWN":"總之我們知道的和你知道的，沒有太大區別。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하지만 반대로 생각해 봐.","JPN":"でも、逆に考えてみろ。","ENG":"But look at it like this.","TWN":"不過反過來想。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"중요한 정보일수록 적에게 알려지는 건 싫어하는 법이거든.","JPN":"重要な情報であればあるほど、敵には知られたくないものだ。","ENG":"The more important the information, the harder people try to hide it.","TWN":"越是重要的情報，就越不想被敵人知道。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"내가 듣기에는 그 여자가 너에게서 필사적으로 감춘다는 인상인데.","JPN":"俺の聞いた感じでは、君に対してあの女は何かを必死に隠そうとしているという印象だ。","ENG":"Sounds like that woman is trying very hard to hide it from you.","TWN":"在我聽起來，那個女人似乎在拼命地向你隱藏什麼。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"と言いますと……","ENG":"That means...","TWN":"那也就說是……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그 여자에게도 소중한 것이 있었다는 뜻이겠네요.","JPN":"あの女にも大事な何かがあった、ということでしょうか。","ENG":"There's something she actually cared about.","TWN":"那個女人也有珍貴的東西吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……자기는 남들에게서 잔뜩 빼앗아갔으면서.","JPN":"……人々からあんなにたくさんものを奪っておいて。","ENG":"...While destroying things other people cared about.","TWN":"……明明自己也從別人那裡搶走了很多東西。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"작동한 거야? 작동한 거 맞지?","JPN":"動いた？　今動いたわよね？","ENG":"Did it work? It worked, right?","TWN":"啟動了嗎？是啟動了沒錯吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 신호가 감지되고 있어. 성공이다.","JPN":"ああ。信号が検知されている。成功だ。","ENG":"Yeah. It's detecting signals. We did it.","TWN":"嗯，感應到訊號了，成功了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"으아아아아!! 봤냐! 관리국 자식들아!","JPN":"うおおおお！！　見たか！　管理局のやつら！","ENG":"AGHHHHH! Eat that! You Administration fools!","TWN":"呃啊啊啊啊！！喂！管理局的蠢蛋們！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"넘버 1……! 우리가 해냈어!! 해냈다고!!","JPN":"ナンバー1……！　私たちやったわ！！　やったのよ！！","ENG":"Number 1...! We did it! We did it!","TWN":"1號……！我們做到了！！做到了！！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"기뻐하는 건 상관없지만 바쁜 나까지 붙잡고 흔들지 마라. 멀미난다.","JPN":"喜ぶのは構わないが、忙しい私まで掴んで揺さぶるのはやめろ。酔ってしまうだろ。","ENG":"You can rejoice all you want, but stop shaking me. I'm getting sick.","TWN":"你開心就開心，不過不要抓著我的肩膀一直晃，晃得我好暈。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 성공입니다! 등대에서 신호가 감지됩니다!","JPN":"司令官。成功です！　灯台からの信号が検知されました！","ENG":"Commander, it's a success! We can detect signals from the Lighthouse!","TWN":"司令官，成功了！燈塔有訊號了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"관측 중인 좌표들이 서서히 안정되고 있습니다.","JPN":"観測中の座標が徐々に安定してきています。","ENG":"The coordinates are slowly stabilizing.","TWN":"觀測中的座標正在慢慢穩定下來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시스템의 연산으로는 앞으로 5분 뒤에 클리파 차원으로 공간 도약이 가능합니다!","JPN":"システムの演算によると、あと5分でクリファ次元への空間跳躍が可能になるようです！","ENG":"According to the system, we can make a space jump to the Qlipha Dimension in 5 minutes!","TWN":"通過系統的運算，接下來5分鐘後就可以朝逆卡巴拉次元進行空間跳躍！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다행이군. 유능한 젊은이들이 많아 정말 다행이야.","JPN":"うむ、有能な若者が多くて幸いだ。","ENG":"Good. We're lucky to have all these talented youths.","TWN":"太好了。有這麼多有能力的年輕人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"더 늦기 전에 여길 벗어난다. 서둘러 인원들을 승선시키도록.","JPN":"これ以上遅れるわけにはいかない。ここを出るぞ。急いでみんなを乗船させろ。","ENG":"We have to get out before it's too late. Get everyone onboard, quickly.","TWN":"抓緊時間讓大家上船，必須趁早離開這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다. 사령관님.","JPN":"かしこまりました。司令官。","ENG":"Yes, Commander.","TWN":"遵命，司令官。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……이, 이건?","JPN":"……こ、これは？","ENG":"...Wh-what?","TWN":"……這，這是？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"무슨 일이지, 카일?","JPN":"どうした、カイル？","ENG":"What is it, Kyle?","TWN":"發生什麼事了，凱爾？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"보고드립니다, 사령관님!","JPN":"報告します、司令官！","ENG":"Reporting, Commander!","TWN":"報告司令官！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"강력한 침식파 반응이 군집 유형의 형태를 형성하면서 아군을 향해 접근 중입니다!","JPN":"強力な侵食波反応が群れの形態を成しながら、こちらに向かって接近中です！","ENG":"A powerful horde-form Corruption ray reaction is approaching our allies!","TWN":"強大的侵蝕波反應正在以群類形態朝著我方靠近！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"침식체 군집? 설마 등대의 신호에 반응한 건가?","JPN":"侵食体の群れだと？　まさか灯台の信号に反応したのか？","ENG":"A horde of C.O.s? Did they react to the signals from the Lighthouse?","TWN":"侵蝕體群？難道是對燈塔訊號的反應？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다기엔…… 수가 너무 많습니다. 이 근방의 침식체는 모두 처리했을 텐데요.","JPN":"それにしては……数が多すぎます。近辺の侵食体はすべて片付けたはずなんですが。","ENG":"There's... too many of them to say. I doubt there were any C.O.s left in the area.","TWN":"可是……數量有點太多了。這附近的侵蝕體應該全都解決了才是。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"허수공간의 특성이에요.","JPN":"虚数空間の特性です。","ENG":"It's the nature of the imaginary space.","TWN":"這是虛數空間的特點。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"시간도, 공간도 어떤 식으로 관측하느냐에 따라 격변하죠.","JPN":"時間も、空間も、観測の仕方によって急激に変化するんです。","ENG":"Time and space can alter drastically, based on how it's observed.","TWN":"時間和空間都會因為觀測的形式而發生劇變。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희에게는 보이지 않는 거리에 있더라도, 저 침식체들에게는 바로 곁에서 신호를 감지했을 수도 있어요.","JPN":"私たちからすれば見えない距離だとしても、侵食体からすれば、すぐ隣で信号を感知したのかもしれません。","ENG":"Even if they're too far for us to see, those C.O.s might've sensed the signals as if they were right next to it.","TWN":"即使是在我們看不到的距離上，對那些侵蝕體來說，也可能就是在旁邊感應到了訊號。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런 말도 안 되는 일이…….","JPN":"あり得ない、そんなの……","ENG":"That doesn't make sense...","TWN":"這種事情不可能……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"충분히 가능해요. 저 침식체들은 이런 환경에서 활동할 수 있도록 적응했을 테니까요.","JPN":"十分に可能です。あの侵食体たちはここの環境下で活動できるように適応しているはずですから。","ENG":"It's still possible. Those C.O.s would've adapted to operating in environments like this.","TWN":"非常有可能。那些侵蝕體應該已經適應了在這樣的環境裡活動。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"큭…….","JPN":"クッ……","ENG":"Argh…","TWN":"呃……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"사령관님, 적 조우까지 30초 남았습니다! 레이더로는 식별이 불가능할 정도의 대군집입니다!","JPN":"司令官、敵と遭遇するまで残り30秒！　レーダーでは識別不能なまでの大きな群れです！","ENG":"30 seconds to enemy encounter, Commander! The horde is too big for our radars to identify!","TWN":"司令官，還剩30秒就要遇上敵人了！是雷達無法完全辨識的超大群體！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……쉽게 보내 주지 않는군.","JPN":"……簡単には行かせてくれないようだな。","ENG":"...Won't let us go easy, huh.","TWN":"……真是死纏爛打啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전 대원에게 전파한다! 전원 전투 태세로!","JPN":"全隊員に伝える！　総員戦闘態勢！","ENG":"All crew members! Get ready for battle!","TWN":"向全體隊員傳達命令！全員保持戰鬥姿態！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"각자의 생존을 우선시하여 신속히 승선하도록!","JPN":"各自生存を最優先にしつつ、速やかに乗船しろ！","ENG":"Prioritize your own survival and swiftly board on the ship!","TWN":"以自身安全為先，迅速登船！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};